const j = $json;

/* =========================
   SYSTEM PROMPT (PL)
   ========================= */
const system = `Jesteś analitykiem biznesowym w zespole **WdrażajAI Client Analysis**. 
Twoim zadaniem jest przygotować profesjonalny **Pre-Call Report** w języku polskim w formacie Markdown.

Raport ma służyć konsultantowi lub handlowcowi do przygotowania się do rozmowy z potencjalnym klientem.

Uwzględnij w nim następujące sekcje (TYTUŁY PO POLSKU):
1️⃣ Profil osoby
2️⃣ Przegląd firmy
3️⃣ Mocne strony / wyróżniki  
4️⃣ Wyzwania / punkty bólu  
5️⃣ Potencjalne obszary AI / automatyzacji  
6️⃣ Rekomendowane punkty rozmowy na callu  
7️⃣ Braki informacyjne  
8️⃣ Skrypt 30-sekundowego otwarcia rozmowy  

Zawsze zachowaj logiczną strukturę i czytelny układ Markdown (nagłówki, listy punktowane, odstępy). 
Nie wymyślaj danych – jeśli czegoś brakuje, wpisz to w sekcji „Braki informacyjne”.

DODATKOWA ZASADA FORMATOWANIA:
- **Nie używaj** składni linków Markdown \`[tekst](url)\`.
- Gdy podajesz link (np. do profilu LinkedIn), wypisz go jako **czysty URL**, np. \`https://linkedin.com/in/...\`.`;

/* =========================
   WEJŚCIA – skąd bierzemy dane
   ========================= */
// ZAWSZE bierzemy adresy bezpośrednio z Webhooka (pewne źródło wejścia)
const companyUrl =
  $('Start').first()?.json._firstItem?.company_url
  || j.company_url
  || $('Start').first()?.json._firstItem?.website
  || $('Start').first()?.json._firstItem?.url
  || '';

const linkedinUrl =
  $('Start').first()?.json._firstItem?.linkedin_url
  || j.linkedin_url
  || '';

// Tekst strony i dane LI bierz WYŁĄCZNIE z $json (bo Code jest po merge’u)
let companyTextRaw = j.company_text;

// Zabezpieczenie na wypadek starszych przebiegów, gdzie company_text mógł być booleanem:
if (typeof companyTextRaw === 'boolean') companyTextRaw = companyTextRaw ? '' : '';

const companyText =
  (companyTextRaw && String(companyTextRaw).trim().length > 0)
    ? String(companyTextRaw).trim().slice(0, 8000)
    : (companyUrl
        ? `Strona podana: ${companyUrl}. Treść strony nie została pobrana (blokada JS/CSP lub brak treści).`
        : '_Brak danych ze strony firmowej._');

const li = j.linkedin_data || {};

/* =========================
   Heurystyki nazwy spółki / osoby do tytułu
   ========================= */
const prospectName =
  li.full_name || li.name || li.person_full_name || '';

let companyName = li.company?.name || li.company || '';
if (!companyName && companyUrl) {
  try {
    const host = new URL(companyUrl).hostname.replace(/^www\./,'');
    companyName = host.split('.')[0].toUpperCase();
  } catch(e) { /* zostaw pustą nazwę */ }
}

const title = `Pre-call Report – ${companyName || companyUrl || 'Firma'}${prospectName ? ' / ' + prospectName : ''}`;

/* =========================
   LinkedIn jako ładny JSON lub info o braku
   ========================= */
const linkedinInfo =
  li && Object.keys(li).length > 0
    ? JSON.stringify(li, null, 2)
    : 'Brak szczegółów — profil LinkedIn nie został pobrany lub nie podano URL.';

/* =========================
   USER PROMPT – dane wejściowe do LLM
   ========================= */
const user = `# ${title}

---

## 🔗 Dane wejściowe
- **COMPANY_URL:** ${companyUrl || 'brak'}
- **LINKEDIN_URL:** ${linkedinUrl || 'brak'}

---

## 🏢 Treść ze strony firmy
${companyText}

---

## 👤 Dane z LinkedIn (JSON)
\`\`\`json
${linkedinInfo}
\`\`\`

---

Na podstawie powyższych danych przygotuj kompletny raport zgodny z instrukcją w system prompt, używając dokładnie polskich tytułów sekcji.`;

/* =========================
   Zwracamy też pola do tematu e-maila
   ========================= */
return [{
  json: {
    system,
    user,
    recipient_email: j.recipient_email || '',
    company_name: companyName || '',
    prospect_name: prospectName || '',
    report_title: title
  }
}];
